import{_ as i,o as a,c as l,ak as s}from"./chunks/framework.Dpc0wyhY.js";const h=JSON.parse('{"title":"Albums","description":"","frontmatter":{},"headers":[],"relativePath":"grindr-api/messaging/albums.md","filePath":"grindr-api/messaging/albums.md"}'),o={name:"grindr-api/messaging/albums.md"};function t(n,e,r,d,c,u){return a(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="albums" tabindex="-1">Albums <a class="header-anchor" href="#albums" aria-label="Permalink to “Albums”">​</a></h1><p>WIP. No idea what SpankBank, pressie albums and paywalled albums are.</p><h2 id="albumexpirationtype" tabindex="-1">AlbumExpirationType <a class="header-anchor" href="#albumexpirationtype" aria-label="Permalink to “AlbumExpirationType”">​</a></h2><ul><li><code>&quot;INDEFINITE&quot;</code> or <code>0</code> — &quot;Indefinitely&quot;</li><li><code>&quot;ONCE&quot;</code> or <code>1</code> — &quot;View Once&quot;, limited by 30 minutes from request</li><li><code>&quot;TEN_MINUTES&quot;</code> or <code>2</code> — &quot;For 10 Minutes&quot;</li><li><code>&quot;ONE_HOUR&quot;</code> or <code>3</code> — &quot;For 60 Minutes&quot;</li><li><code>&quot;ONE_DAY&quot;</code> or <code>4</code> — &quot;For 24 Hours&quot;</li></ul><p>Previously shared <a href="/grindr-api/messaging/messages#album">albums in chat</a> inherit new <code>expirationType</code> settings from newer sharings of the album.</p><h2 id="albumpreview" tabindex="-1">AlbumPreview <a class="header-anchor" href="#albumpreview" aria-label="Permalink to “AlbumPreview”">​</a></h2><ul><li><code>albumId</code> — long integer</li><li><code>albumNumber</code> — integer or <code>null</code> if album has expired or was locked</li><li><code>totalAlbumsShared</code> — integer or <code>null</code> if album has expired or was locked</li><li><code>hasUnseenContent</code> — boolean</li></ul><h2 id="albummin" tabindex="-1">AlbumMin <a class="header-anchor" href="#albummin" aria-label="Permalink to “AlbumMin”">​</a></h2><ul><li><em>everything from <a href="#albumpreview">AlbumPreview</a></em></li><li><code>albumName</code> — appears to always be <code>null</code></li><li><code>profileId</code> — integer</li><li><code>albumViewable</code> — boolean</li></ul><h2 id="albumdetails" tabindex="-1">AlbumDetails <a class="header-anchor" href="#albumdetails" aria-label="Permalink to “AlbumDetails”">​</a></h2><ul><li><code>sharedCount</code> — integer</li><li><code>createdAt</code> — string, date formatted as ISO 8601, e.g. <code>2026-03-27T20:39:00</code></li><li><code>updatedAt</code> — string, date formatted as ISO 8601, e.g. <code>2026-03-27T20:39:00</code></li></ul><h2 id="albumexpiration" tabindex="-1">AlbumExpiration <a class="header-anchor" href="#albumexpiration" aria-label="Permalink to “AlbumExpiration”">​</a></h2><ul><li><code>expiresAt</code> — unix timestamp in milliseconds or <code>null</code></li><li><code>expirationType</code> — <a href="#albumexpirationtype">AlbumExpirationType</a></li></ul><h2 id="albumcontentmin" tabindex="-1">AlbumContentMin <a class="header-anchor" href="#albumcontentmin" aria-label="Permalink to “AlbumContentMin”">​</a></h2><ul><li><code>contentId</code> — long integer</li><li><code>contentType</code> — string</li><li><code>coverUrl</code> — <a href="#albumcoverurl">AlbumCoverUrl</a></li><li><code>statusId</code> — unknown integer, WIP</li></ul><h2 id="albumcontent" tabindex="-1">AlbumContent <a class="header-anchor" href="#albumcontent" aria-label="Permalink to “AlbumContent”">​</a></h2><ul><li><em>everything from <a href="#albumcontentmin">AlbumContentMin</a></em></li><li><code>thumbUrl</code> — string, unblurred preview, see <a href="/grindr-api/media/signed-cdn-files">Media -&gt; Signed CDN files</a></li><li><code>url</code> — string, original file, see <a href="/grindr-api/media/signed-cdn-files">Media -&gt; Signed CDN files</a>, may be <code>&quot;&quot;</code> if <code>remainingViews</code> is 0</li><li><code>processing</code> — boolean</li><li><code>rejectionId</code> - unknown or <code>null</code></li></ul><h2 id="albumcoverurl" tabindex="-1">AlbumCoverUrl <a class="header-anchor" href="#albumcoverurl" aria-label="Permalink to “AlbumCoverUrl”">​</a></h2><p>String with URL or <code>null</code>, blurred downscaled preview.</p><p>JPEG photo with the first frame of video in case of video files.</p><p>Becomes unavailable (<code>AccessDenied</code>) after album has expired.</p><p>See <a href="/grindr-api/media/signed-cdn-files">Media -&gt; Signed CDN files</a>.</p><h2 id="album-name" tabindex="-1">Album name <a class="header-anchor" href="#album-name" aria-label="Permalink to “Album name”">​</a></h2><p>String, may be empty (<code>&quot;&quot;</code>) or <code>null</code>, non-string values are coerced into string.</p><p>Maximum length: 255 UTF-8 bytes, which is 255 characters for ASCII strings (1 ASCII character is encoded as 1 byte) but less if you include emojis or non-ascii characters (2+ bytes/one codepoit).</p><h2 id="get-my-albums" tabindex="-1">Get my albums <a class="header-anchor" href="#get-my-albums" aria-label="Permalink to “Get my albums”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v1/albums</span></span></code></pre></div><p>Response:</p><ul><li><code>albums</code> — array of objects <ul><li><em>everything from <a href="#albumdetails">AlbumDetails</a></em></li><li><code>albumId</code> — long integer</li><li><code>albumName</code> — <a href="#album-name">Album name</a></li><li><code>profileId</code> — integer</li><li><code>version</code> — integer</li><li><code>content</code> — <a href="#albumcontent">AlbumContent</a></li><li><code>isShareable</code> — boolean</li></ul></li></ul><h2 id="get-an-album" tabindex="-1">Get an album <a class="header-anchor" href="#get-an-album" aria-label="Permalink to “Get an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v2/albums/{albumId}</span></span></code></pre></div><p>Response:</p><ul><li><em>everything from <a href="#albummin">AlbumMin</a></em></li><li><em>everything from <a href="#albumdetails">AlbumDetails</a></em></li><li><code>content</code> — array of objects <ul><li><em>everything from <a href="#albumcontent">AlbumContent</a></em></li><li><code>remainingViews</code> — integer, might be -1; absent if this is your album</li></ul></li></ul><p>Errors:</p><ul><li>HTTP status 403 — if you don&#39;t have access to album or it doesn&#39;t exist</li></ul><h2 id="get-an-album-media-poster" tabindex="-1">Get an album media poster <a class="header-anchor" href="#get-an-album-media-poster" aria-label="Permalink to “Get an album media poster”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v1/albums/{albumId}/content/{contentId}/poster</span></span></code></pre></div><p>Response:</p><ul><li><code>blurredPosterUrl</code> — string, see <a href="/grindr-api/media/signed-cdn-files">Media -&gt; Signed CDN files</a></li><li><code>posterUrl</code> — string, see <a href="/grindr-api/media/signed-cdn-files">Media -&gt; Signed CDN files</a></li></ul><h2 id="record-view-of-an-album" tabindex="-1">Record view of an album <a class="header-anchor" href="#record-view-of-an-album" aria-label="Permalink to “Record view of an album”">​</a></h2><p>Repeated requests after invoking this endpoint on view ONCE albums cause HTTP status 403 Forbidden and <code>Action not permitted</code> error.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v3/albums/{albumId}/view</span></span></code></pre></div><p>Response:</p><p>Empty</p><h2 id="record-view-of-media-in-an-album" tabindex="-1">Record view of media in an album <a class="header-anchor" href="#record-view-of-media-in-an-album" aria-label="Permalink to “Record view of media in an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Repeated requests after reaching remainingViews=0 do not cause any errors.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v1/albums/{albumId}/view/content/{contentId}</span></span></code></pre></div><p>Response:</p><ul><li><code>remainingViews</code> — integer</li></ul><h2 id="get-info-about-profile-s-album" tabindex="-1">Get info about profile&#39;s album <a class="header-anchor" href="#get-info-about-profile-s-album" aria-label="Permalink to “Get info about profile&#39;s album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v2/albums/shares</span></span></code></pre></div><p>Body:</p><ul><li><code>profileId</code> — integer</li></ul><p>Response:</p><ul><li><code>profileId</code> — long integer</li><li><code>hasAlbum</code> — boolean</li><li><code>hasSharedWithMe</code> — boolean</li></ul><h2 id="get-albums-shared-by-a-profile" tabindex="-1">Get albums shared by a profile <a class="header-anchor" href="#get-albums-shared-by-a-profile" aria-label="Permalink to “Get albums shared by a profile”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v2/albums/shares/{profileId}</span></span></code></pre></div><p>Response:</p><ul><li><code>albums</code> — array of objects <ul><li><em>everything from <a href="#albummin">AlbumMin</a></em></li><li><em>everything from <a href="#albumexpiration">AlbumExpiration</a></em></li><li><code>content</code> — a single <a href="#albumcontentmin">AlbumContentMin</a>, a blurred preview</li><li><code>contentCount</code> — object <ul><li><code>imageCount</code> — integer</li><li><code>videoCount</code> — integer</li></ul></li></ul></li></ul><h2 id="create-an-album" tabindex="-1">Create an album <a class="header-anchor" href="#create-an-album" aria-label="Permalink to “Create an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v2/albums</span></span></code></pre></div><p>Body:</p><ul><li><code>albumName</code> — <a href="#album-name">Album name</a></li></ul><p>Response:</p><ul><li><code>albumId</code> — long integer</li></ul><p>Error:</p><ul><li>HTTP status 402 Payment required if you reached <a href="#get-album-limits">limit</a> for number of created albums</li></ul><h2 id="rename-an-album" tabindex="-1">Rename an album <a class="header-anchor" href="#rename-an-album" aria-label="Permalink to “Rename an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PUT /v2/albums/{albumId}</span></span></code></pre></div><p>Body:</p><ul><li><code>albumName</code> — <a href="#album-name">Album name</a></li></ul><p>Response:</p><ul><li><code>albumId</code> — integer</li><li><code>albumName</code> — <a href="#album-name">Album name</a></li></ul><h2 id="delete-an-album" tabindex="-1">Delete an album <a class="header-anchor" href="#delete-an-album" aria-label="Permalink to “Delete an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Repeated requests cause 403 Forbidden and <code>Action not permitted</code> error.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>DELETE /v1/albums/{albumId}</span></span></code></pre></div><p>Response:</p><p>Empty</p><h2 id="upload-media-to-an-album" tabindex="-1">Upload media to an album <a class="header-anchor" href="#upload-media-to-an-album" aria-label="Permalink to “Upload media to an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Repeated requests with the same file (its contents) are skipped and a cached result from the first upload request is returned.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v1/albums/{albumId}/content</span></span></code></pre></div><p>Query:</p><ul><li><code>width</code> — number, optional, doesn&#39;t affect the resulting image</li><li><code>height</code> — number, optional, doesn&#39;t affect the resulting image</li><li><code>isFresh</code> — boolean, optional, unknown how it affects the resulting image, WIP</li></ul><p>Body:</p><p>Content-Type: multipart/form-data</p><ul><li><code>content</code> — file to upload</li></ul><p>Response:</p><ul><li><code>contentId</code> — Media file ID</li><li><code>contentUrl</code> — <code>null</code></li></ul><h2 id="reorder-media-in-an-album" tabindex="-1">Reorder media in an album <a class="header-anchor" href="#reorder-media-in-an-album" aria-label="Permalink to “Reorder media in an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v1/albums/{albumId}/content/order</span></span></code></pre></div><p>Body:</p><ul><li><code>contentIds</code> — array of long integers, each Media file ID must appear exactly once</li></ul><h2 id="delete-media-from-an-album" tabindex="-1">Delete media from an album <a class="header-anchor" href="#delete-media-from-an-album" aria-label="Permalink to “Delete media from an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Technically, this does not delete the media from CDN. All signed URLs will continue to work until expired. Uploading same file will result in getting it assigned the same <code>contentId</code>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>DELETE /v1/albums/{albumId}/content/{contentId}</span></span></code></pre></div><p>Response:</p><p>Empty</p><h2 id="albums-content-processing-wip" tabindex="-1">Albums content processing, WIP <a class="header-anchor" href="#albums-content-processing-wip" aria-label="Permalink to “Albums content processing, WIP”">​</a></h2><p>WIP</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v1/albums/{albumId}/content/{contentId}/processing</span></span></code></pre></div><p>Response:</p><ul><li><code>processing</code> — boolean</li></ul><h2 id="pics-wip" tabindex="-1">Pics, WIP <a class="header-anchor" href="#pics-wip" aria-label="Permalink to “Pics, WIP”">​</a></h2><ul><li>GET /v1/pics/limited/status . UnlimitedPhotoStatusResponse</li></ul><p>Response:</p><ul><li>available — integer</li><li>total — integer</li></ul><h2 id="pics-expiring-wip" tabindex="-1">Pics expiring, WIP <a class="header-anchor" href="#pics-expiring-wip" aria-label="Permalink to “Pics expiring, WIP”">​</a></h2><ul><li>POST /v4/pics/expiring ExpiringPhotoReportSentRequest ExpiringPhotoStatusResponse</li></ul><h2 id="pics-expiring-status-wip" tabindex="-1">Pics expiring status, WIP <a class="header-anchor" href="#pics-expiring-status-wip" aria-label="Permalink to “Pics expiring status, WIP”">​</a></h2><ul><li>GET /v4/pics/expiring/status . ExpiringPhotoStatusResponse</li></ul><h2 id="videos-expiring-status-wip" tabindex="-1">Videos expiring status, WIP <a class="header-anchor" href="#videos-expiring-status-wip" aria-label="Permalink to “Videos expiring status, WIP”">​</a></h2><ul><li>GET /v4/videos/expiring/status . PrivateVideoStatusResponse</li></ul><h2 id="get-album-shares" tabindex="-1">Get album shares <a class="header-anchor" href="#get-album-shares" aria-label="Permalink to “Get album shares”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Returns profiles the album was shared with.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v1/albums/{albumId}/shares</span></span></code></pre></div><p>Response:</p><ul><li><code>profileIds</code> — array of integers</li></ul><h2 id="share-an-album" tabindex="-1">Share an album <a class="header-anchor" href="#share-an-album" aria-label="Permalink to “Share an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Automatically sends the shared album to chat with all listed profiles.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/albums/{albumId}/shares</span></span></code></pre></div><p>Body:</p><ul><li><code>profiles</code> — array of objects <ul><li><code>expirationType</code> — <a href="#albumexpirationtype">AlbumExpirationType</a></li><li><code>profileId</code> — integer</li></ul></li></ul><p>Response:</p><p>Empty</p><h2 id="unshare-an-album" tabindex="-1">Unshare an album <a class="header-anchor" href="#unshare-an-album" aria-label="Permalink to “Unshare an album”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PUT /v1/albums/{albumId}/unshares</span></span></code></pre></div><p>Body:</p><ul><li><code>profiles</code> — array of objects <ul><li><code>profileId</code> — long integer</li><li><code>shareId</code> — unknown integer, can be <code>0</code></li></ul></li></ul><p>Response:</p><p>Empty</p><h2 id="unshare-an-album-from-everybody" tabindex="-1">Unshare an album from everybody <a class="header-anchor" href="#unshare-an-album-from-everybody" aria-label="Permalink to “Unshare an album from everybody”">​</a></h2><p>WIP</p><p>Unknown, returns 403</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PUT /v1/albums/{albumId}/shares/remove</span></span></code></pre></div><h2 id="albums-content-chat-list-by-id-wip" tabindex="-1">Albums content chat list-by-id, WIP <a class="header-anchor" href="#albums-content-chat-list-by-id-wip" aria-label="Permalink to “Albums content chat list-by-id, WIP”">​</a></h2><p>WIP</p><p>Unknown, <code>{&quot;ids&quot;:[852120758]}</code> returns 400</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v1/albums/{albumId}/content/chat/list-by-id</span></span></code></pre></div><p>Query:</p><ul><li><code>isFresh</code> — boolean</li></ul><p>Body:</p><ul><li><code>ids</code> — array of long integers</li></ul><h2 id="get-album-limits" tabindex="-1">Get album limits <a class="header-anchor" href="#get-album-limits" aria-label="Permalink to “Get album limits”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v1/albums/storage</span></span></code></pre></div><p><em>Interestingly, /v2/albums/storage appears to exist, though not used in current version of APK.</em></p><p>Response:</p><ul><li><code>subscriptionType</code> — string, e.g. <code>FreeAlbums</code></li><li><code>maxAlbums</code> — integer</li><li><code>maxContentItemsPerAlbum</code> — integer</li><li><code>maxShares</code> — integer</li><li><code>maxViewableAlbums</code> — integer</li><li><code>maxViewableVideos</code> — integer</li><li><code>maxContentSize</code> — long integer, size in bytes</li><li><code>maxContentSizeHumanReadable</code> — string, incorrectly uses decimal multiples notation (MB) when in fact calculates binary notation (MiB), so API&#39;s <code>120.00 MB</code> is actually 120 MiB or 125.8291 MB</li><li><code>maxVideoLength</code> — long integer, length in milliseconds (1/1000th of a second)</li><li><code>minVideoLength</code> — long integer, length in milliseconds (1/1000th of a second)</li><li><code>maxShareableAlbums</code> — integer</li><li><code>maxVideosPerAlbum</code> — integer</li></ul><h2 id="albums-red-dot-wip" tabindex="-1">Albums red dot, WIP <a class="header-anchor" href="#albums-red-dot-wip" aria-label="Permalink to “Albums red dot, WIP”">​</a></h2><p>This may just be tracking but could also be related to something else</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PUT /v1/albums/red-dot</span></span></code></pre></div><p>Response:</p><p>Empty.</p><h2 id="gets-albums-shared-with-us" tabindex="-1">Gets albums shared with us <a class="header-anchor" href="#gets-albums-shared-with-us" aria-label="Permalink to “Gets albums shared with us”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v3/pressie-albums/feed</span></span></code></pre></div><p>Body:</p><ul><li><code>isFavorite</code> — boolean, optional, only albums shared by <a href="/grindr-api/users/favorites">favorite</a> users</li><li><code>isOnline</code> — boolean, optional, only albums shared by currently online users</li><li><code>onlyVideo</code> — boolean, optional, only albums with at least one video</li><li><code>blur</code> — boolean, optional, blur media urls in response</li></ul><p>Response:</p><ul><li><code>profileFeeds</code> - array of objects <ul><li><code>profileId</code> — integer</li><li><code>paywallStatus</code> — string, e.g. <code>ALLOW</code></li><li><code>seen</code> - boolean</li><li><code>content</code> — object</li><li><code>profile</code> — object <ul><li><code>profileId</code> — long integer</li><li><code>name</code> — string, may be empty</li><li><code>profileUrl</code> — string or <code>null</code></li><li><code>onlineUntil</code> — unknown or <code>null</code></li><li><code>distanceKm</code> — float or <code>null</code></li></ul></li></ul></li><li><code>sharedAlbums</code> - array of objects <ul><li><em>everything from <a href="#albumpreview">AlbumPreview</a></em></li><li><code>albumViewable</code> — boolean</li><li><code>albumVersion</code> — integer</li><li><code>expiresat</code> — unix timestamp in milliseconds or <code>null</code> (observed key spelling; may also appear as <code>expiresAt</code>)</li><li><code>name</code> — <a href="#album-name">Album name</a></li><li><code>ownerProfileId</code> — integer</li><li><code>imageCount</code> — integer</li><li><code>videoCount</code> — integer</li><li><code>coverContent</code> — object <ul><li><code>id</code> — long integer</li><li><code>contentType</code> — string</li><li><code>coverContent</code> — <a href="#albumcoverurl">AlbumCoverUrl</a></li><li><code>status</code> — string, e.g. <code>ACTIVE</code></li></ul></li><li><code>profile</code> — object <ul><li><code>profileId</code> — long integer</li><li><code>name</code> — string, may be empty</li><li><code>profileUrl</code> — string or <code>null</code></li><li><code>onlineUntil</code> — unknown or <code>null</code></li><li><code>distanceKm</code> — float or <code>null</code></li></ul></li></ul></li><li><code>experimentStatus</code> - number</li><li><code>nonEmptyPersonalAlbumCount</code> - number</li><li><code>emptyAlbumId</code> - <code>null</code></li></ul><h2 id="pressie-albums-feed-paywall" tabindex="-1">Pressie albums feed paywall <a class="header-anchor" href="#pressie-albums-feed-paywall" aria-label="Permalink to “Pressie albums feed paywall”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v3/pressie-albums/feed/paywall/</span></span></code></pre></div><p>No body.</p><p>Response:</p><ul><li><code>albumPaywallContent</code> - array of objects <ul><li><code>albumId</code> — long integer</li><li><code>profile</code> — object <ul><li><code>profileId</code> — long integer</li><li><code>name</code> — string, may be empty</li><li><code>profileUrl</code> — string or <code>null</code></li><li><code>onlineUntil</code> — unknown or <code>null</code></li><li><code>distanceKm</code> — float or <code>null</code></li></ul></li><li><code>paywallCoverUrl</code> — string, see <a href="/grindr-api/media/signed-cdn-files">Media -&gt; Signed CDN files</a></li><li><code>paywallUrls</code> — array of strings, see <a href="/grindr-api/media/signed-cdn-files">Media -&gt; Signed CDN files</a></li><li><code>albumsItemCount</code> — integer</li></ul></li></ul><h2 id="pressie-albums-feed-profile-id-wip" tabindex="-1">Pressie albums feed profile ID, WIP <a class="header-anchor" href="#pressie-albums-feed-profile-id-wip" aria-label="Permalink to “Pressie albums feed profile ID, WIP”">​</a></h2><p>WIP</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v3/pressie-albums/feed/{profileId}</span></span></code></pre></div><h2 id="pressie-albums-feed-update-read-wip" tabindex="-1">Pressie albums feed update read, WIP <a class="header-anchor" href="#pressie-albums-feed-update-read-wip" aria-label="Permalink to “Pressie albums feed update read, WIP”">​</a></h2><p>WIP</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v3/pressie-albums/feed/update/read</span></span></code></pre></div>',186)])])}const b=i(o,[["render",t]]);export{h as __pageData,b as default};
